class Solution {
    public int strangePrinter(String s) {
        int n = s.length();
        int[][] dp = new int[n + 1][n + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                dp[i][j] = -1;
            }
        }
        return helper(s, 0, n - 1, dp);
    }

    private int helper(String s, int left, int right, int[][] dp) {
        if (left > right) {
            return 0;
        }
        if (dp[left][right] != -1) {
            return dp[left][right];
        }
        int ans = 1 + helper(s, left + 1, right, dp);
        for (int i = left + 1; i <= right; i++) {
            if (s.charAt(left) == s.charAt(i)) {
                ans = Math.min(ans, helper(s, left, i - 1, dp) + helper(s, i + 1, right, dp));
            }
        }
        dp[left][right] = ans;
        return ans;
    }
}
